`,r:{minutes:.04,words:13},y:"a",t:"MATH011"}}],["/academics/MATH011/lect01.html",{loader:()=>e(()=>import("./lect01.html-cbyicT4-.js"),__vite__mapDeps([29,1])),meta:{e:`
